let FBOrganic_totalFollowers = 0;
for (const metric of viewsFollowersData) {
  if (metric.name === "page_media_view") {
    FBOrganic_totalViews = metric.values.reduce((sum, v) => sum + v.value, 0);
  }
  if (metric.name === "page_daily_follows_unique") {
    FBOrganic_totalFollowers = metric.values.reduce((sum, v) => sum + v.value, 0);
  }
}

// ---------- Likes and Engagements (daily values arrays) ----------
const likesEngagementsData = $('FB Organic: Likes and Shares').first().json.data;
let FBOrganic_totalLikes = 0;
let FBOrganic_totalEngagements = 0;
for (const metric of likesEngagementsData) {
  if (metric.name === "page_actions_post_reactions_like_total") {
    FBOrganic_totalLikes = metric.values.reduce((sum, v) => sum + v.value, 0);
  }
  if (metric.name === "page_post_engagements") {
    // NOTE: This is the closest proxy for "shares" — it includes
    // likes + comments + shares + other interactions combined.
    // No standalone page-level shares metric exists in the FB API.
    FBOrganic_totalEngagements = metric.values.reduce((sum, v) => sum + v.value, 0);
  }
}

// ---------- Return totals ----------
return [
  {
    json: {
      FBOrganic_totalViews,
      FBOrganic_totalFollowers,
      FBOrganic_totalLikes,
      FBOrganic_totalEngagements,
    }
  }
];

