// Get raw output from previous node
let raw = $input.first().json.output[0].content[0].text;

// Ensure it's a string
if (typeof raw !== 'string') {
  throw new Error('Input is not a string');
}

// Remove markdown code block wrappers
raw = raw
  .replace(/^\s*```json\s*|^\s*```\s*/gi, '')
  .replace(/```$/, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error('Failed to parse JSON: ' + error.message);
}

// Return proper JSON object
return [
  {
    json: parsed
  }
];

// Get all input data
const allData = $input.all().map(item => item.json);

// Initialize structures
const paid = { youtube: {}, facebook: {}, instagram: {}, totals: {} };
const organic = { youtube: {}, facebook: {}, instagram: {}, totals: {} };
const prior_week = { 
  organic_views: 0, 
  organic_followers: 0,
  //organic_est_mins_watched: 0
};
const calculated = {};
const targets = {};
const vs_target = {};

// Helper to sum totals
function sum(values) {
  return values.reduce((a, b) => a + (b || 0), 0);
}

// ---- 1️⃣ Separate Paid & Organic ----
allData.forEach(data => {
  Object.keys(data).forEach(key => {
    const value = Number(data[key]) || 0;

    // ===== PAID METRICS =====
    if (key.endsWith("Paid_totalSpend")) {
      if (key.startsWith("YT")) paid.youtube.spend = value;
      if (key.startsWith("FB")) paid.facebook.spend = value;
      if (key.startsWith("IG")) paid.instagram.spend = value;
    }
    if (key.endsWith("Paid_totalViews")) {
      if (key.startsWith("YT")) paid.youtube.views = value;
      if (key.startsWith("FB")) paid.facebook.views = value;
      if (key.startsWith("IG")) paid.instagram.views = value;
    }
    if (key.endsWith("Paid_totalLikes")) {
      if (key.startsWith("YT")) paid.youtube.likes = value;
      if (key.startsWith("FB")) paid.facebook.likes = value;
      if (key.startsWith("IG")) paid.instagram.likes = value;
    }
    if (key.endsWith("Paid_totalShares")) {
      if (key.startsWith("YT")) paid.youtube.shares = value;
      if (key.startsWith("FB")) paid.facebook.shares = value;
      if (key.startsWith("IG")) paid.instagram.shares = value;
    }
    if (key.endsWith("Paid_totalFollowers")) {
      if (key.startsWith("YT")) paid.youtube.new_followers = value;
      if (key.startsWith("FB")) paid.facebook.new_followers = value;
      if (key.startsWith("IG")) paid.instagram.new_followers = value;
    }

    // Capture CPV, CPL, CPS, CPF per platform
    if (key.endsWith("Paid_CPV")) {
      if (key.startsWith("YT")) paid.youtube.cpv = value;
      if (key.startsWith("FB")) paid.facebook.cpv = value;
      if (key.startsWith("IG")) paid.instagram.cpv = value;
    }
    if (key.endsWith("Paid_CPL")) {
      if (key.startsWith("YT")) paid.youtube.cpl = value;
      if (key.startsWith("FB")) paid.facebook.cpl = value;
      if (key.startsWith("IG")) paid.instagram.cpl = value;
    }
    if (key.endsWith("Paid_CPS")) {
      if (key.startsWith("YT")) paid.youtube.cps = value;
      if (key.startsWith("FB")) paid.facebook.cps = value;
      if (key.startsWith("IG")) paid.instagram.cps = value;
    }
    if (key.endsWith("Paid_CPF")) {
      if (key.startsWith("YT")) paid.youtube.cpf = value;
      if (key.startsWith("FB")) paid.facebook.cpf = value;
      if (key.startsWith("IG")) paid.instagram.cpf = value;
    }

    // ===== ORGANIC METRICS =====
    if (key.endsWith("Organic_totalViews")) {
      if (key.startsWith("YT")) organic.youtube.views = value;
      if (key.startsWith("FB")) organic.facebook.views = value;
      if (key.startsWith("IG")) organic.instagram.views = value;
    }
    if (key.endsWith("Organic_totalLikes")) {
      if (key.startsWith("YT")) organic.youtube.likes = value;
      if (key.startsWith("FB")) organic.facebook.likes = value;
      if (key.startsWith("IG")) organic.instagram.likes = value;
    }
    if (key.endsWith("Organic_totalShares")) {
      if (key.startsWith("YT")) organic.youtube.shares = value;
      if (key.startsWith("FB")) organic.facebook.shares = value;
      if (key.startsWith("IG")) organic.instagram.shares = value;
    }
    if (key.endsWith("Organic_totalFollowers")) {
      if (key.startsWith("YT")) organic.youtube.new_followers = value;
      if (key.startsWith("FB")) organic.facebook.new_followers = value;
      if (key.startsWith("IG")) organic.instagram.new_followers = value;
    }

    // Estimated minutes watched (YouTube)
    if (key === "YTOrganic_estMinsWatched") {
      organic.youtube.est_mins_watched = value;
    }

    // PRIOR WEEK (only organic)
    if (key.endsWith("Organic_totalViews_PRIOR")) prior_week.organic_views += value;
    if (key.endsWith("Organic_totalFollowers_PRIOR")) prior_week.organic_followers += value;
    //if (key === "YTOrganic_estMinsWatched_PRIOR") {
    //  prior_week.organic_est_mins_watched = value;
    //}

